from fastapi import APIRouter, Depends, HTTPException, status from sqlalchemy.ext.asyncio import AsyncSession
from app.dependencies import get_db, get_current_user, DBSession, CurrentUser from app.schemas.users import UserCreate, UserResponse from app.services import users as user_service
router = APIRouter()
@router.post("/", response_model=UserResponse, status_code=status.HTTP_201_CREATED) async def create_user(user_data: UserCreate, db: DBSession) -> UserResponse: return await user_service.create_user(db, user_data)
@router.get("/me", response_model=UserResponse) async def get_me(current_user: CurrentUser) -> UserResponse: return current_user

from fastapi import APIRouter, BackgroundTasks

router = APIRouter()


def send_email(email: str, message: str) -> None:
    # Email sending logic (runs after response is returned)
    pass


@router.post("/notify")
async def send_notification(
    email: str, message: str, background_tasks: BackgroundTasks
) -> dict:
    background_tasks.add_task(send_email, email, message)
    return {"status": "notification queued"}
